import * as pdfjs from 'pdfjs-dist/legacy/build/pdf.mjs';
import { readFileSync } from 'fs';

const buf = readFileSync\('pdf-test/INFORME ISAK II NICO PEREYRA.pdf'\);
const loadingTask = pdfjs.getDocument\({ data: new Uint8Array\(buf\), verbosity: 0 }\);
const pdf = await loadingTask.promise;
const items = [];
for \(let p = 1; p <= pdf.numPages; p++\) {
  const page = await pdf.getPage\(p\);
  const content = await page.getTextContent\(\);
  for \(const item of content.items\) {
    const str = item.str?.trim\(\);
    if \(str\) items.push\({ text: str, x: Math.round\(item.transform[4]\), y: Math.round\(item.transform[5]\) }\);
  }
}
// Sort by y desc then x asc
items.sort\(\(a,b\) => b.y - a.y || a.x - b.x\);
console.log\(JSON.stringify\(items, null, 2\)\);
